const fs = require('fs');
const config = $('Set Configuration').first().json.config;

// Check file mount and inputs
try {
  if (!fs.existsSync(config.EXCEL_FILE)) {
    throw new Error(`Excel file not found at: ${config.EXCEL_FILE}`);
  }
  if (!fs.existsSync(config.SOURCE_PDF_DIR)) {
    throw new Error(`PDF Source directory not found at: ${config.SOURCE_PDF_DIR}`);
  }

  const files = fs.readdirSync(config.SOURCE_PDF_DIR);

  // Check write permission to log path
  fs.writeFileSync(`${config.LOG_PATH}/.preflight_ok`, new Date().toISOString());

  // Grab categories out of the previous node (Fetch Categories) if available
  // otherwise use fallback array
  let categories = ['Correspondence','RFA','Drawing','Transmittal','Report','Other'];
  try {
    const upstreamData = $('Fetch Categories').first()?.json?.data;
    if (upstreamData && Array.isArray(upstreamData)) {
        categories = upstreamData.map(c => c.name || c.type || c); // very loose mapping depending on API response
    }
  } catch(e) {}

  // Grab existing tags from Fetch Tags node
  let existingTags = [];
  try {
    const tagData = $('Fetch Tags').first()?.json?.data || [];
    existingTags = Array.isArray(tagData) ? tagData.map(t => t.tag_name || t.name || '').filter(Boolean) : [];
  } catch(e) {}

  return [{ json: { 
    preflight_ok: true, 
    pdf_count_in_source: files.length,
    excel_target: config.EXCEL_FILE,
    system_categories: categories,
    existing_tags: existingTags,
    timestamp: new Date().toISOString()
  }}];
} catch (err) {
  throw new Error(`Pre-flight check failed: ${err.message}`);
}

const cpJson = $input.first()?.json || {};
const startIndex = cpJson.last_processed_index || 0;
const config = $('Set Configuration').first().json.config;

const allItems = $('Read Excel').all().map(i => i.json);
const remaining = allItems.slice(startIndex);
const currentBatch = remaining.slice(0, config.BATCH_SIZE);

// Encoding Normalization
const normalize = (str) => {
  if (!str) return '';
  return String(str).normalize('NFC').trim();
};

return currentBatch.map((item, i) => {
  const docNum = item.document_number || item.correspondence_number || item['Document Number'] || item['Corr. No.'];
  // Use File name from Excel directly - must exist
  const excelFileName = item['File name'] || item.file_name || item['File Name'] || item.filename;
  if (!excelFileName) {
    throw new Error(`Missing 'File name' column for row ${i + startIndex + 1}, document: ${docNum}`);
  }
  const fileName = normalize(excelFileName);
  return {
    json: {
      document_number: normalize(docNum),
      title: normalize(item.title || item.Title || item['Subject']),
      legacy_number: normalize(item.legacy_number || item['Legacy Number'] || item['Response Doc.'] || ''),
      excel_revision: item.revision || item.Revision || item.rev || 1,
      original_index: startIndex + i,
      batch_id: config.BATCH_ID,
      file_name: fileName,
      issued_date: normalize(item.issued_date || item.Issued_date || item['Issued Date'] || item.date || item.Date || item.document_date || item.Document_Date),
      received_date: normalize(item.received_date || item.Received_date || item['Received Date'] || item.receive || item.Receive),
      correspondence_type: normalize(item.correspondence_types || item.correspondence_type || item['Correspondence Types'] || item['Correspondence Type'])
    }
  };
});

const fs = require('fs');
const path = require('path');
const config = $('Set Configuration').first().json.config;

const items = $input.all();
if (!items || items.length === 0) return [];

const validated = [];
const errors = [];

for (const item of items) {
  const fileName = item.json?.file_name;
  if (!fileName) {
    errors.push({
      ...item,
      json: { ...item.json, file_valid: false, error: 'file_name is missing', error_type: 'MISSING_FILENAME', file_exists: false }
    });
    continue;
  }

  // Use file name from Excel directly, add .pdf if missing
  let safeName = path.basename(String(fileName)).normalize('NFC');
  if (!safeName.toLowerCase().endsWith('.pdf')) {
    safeName += '.pdf';
  }
  const filePath = path.resolve(config.SOURCE_PDF_DIR, safeName);

  // Path traversal check
  if (!filePath.startsWith(path.resolve(config.SOURCE_PDF_DIR))) {
    errors.push({
      ...item,
      json: { ...item.json, file_valid: false, error: 'Path traversal detected', error_type: 'SECURITY', file_exists: false }
    });
    continue;
  }

  try {
    if (fs.existsSync(filePath)) {
      const stats = fs.statSync(filePath);
      validated.push({
        ...item,
        json: { ...item.json, file_valid: true, file_exists: true, file_size: stats.size, file_path: filePath }
      });
    } else {
      errors.push({
        ...item,
        json: { ...item.json, file_valid: false, error: `File not found: ${safeName}`, error_type: 'FILE_NOT_FOUND', file_exists: false }
      });
    }
  } catch (err) {
    errors.push({
      ...item,
      json: { ...item.json, file_valid: false, error: err.message, error_type: 'FILE_ERROR', file_exists: false }
    });
  }
}

return [...validated, ...errors];

const config = $('Set Configuration').first().json.config;
const fallbackState = $('Check Fallback State').first()?.json || { is_fallback_active: false, recent_error_count: 0 };
const isFallback = fallbackState.is_fallback_active || false;
const model = isFallback ? config.OLLAMA_MODEL_FALLBACK : config.OLLAMA_MODEL_PRIMARY;

// Read DB Context
const dbContext = $('Fetch DB Context').all().map(i => i.json);
const dbProjects = dbContext.filter(d => d.type === 'projects').map(d => ({id: d.id, code: d.text1, name: d.text2}));
const dbDisciplines = dbContext.filter(d => d.type === 'disciplines').map(d => ({id: d.id, th: d.text1, en: d.text2}));
const dbOrgs = dbContext.filter(d => d.type === 'organizations').map(d => ({id: d.id, name: d.text1, code: d.text2}));
const dbTags = dbContext.filter(d => d.type === 'tags').map(d => ({id: d.id, name: d.text1}));
const dbCorrTypes = dbContext.filter(d => d.type === 'correspondence_types').map(d => ({id: d.id, code: d.text1, name: d.text2}));

let systemCategories = ['Correspondence','RFA','Drawing','Transmittal','Report','Other'];
try { systemCategories = $('File Mount Check').first().json.system_categories || systemCategories; } catch (e) {}

const items = $('Extract PDF Text').all();

return items.map(item => {
  const docNum = String(item.json.document_number || '');
  const title = String(item.json.title || '');
  const legacyNum = String(item.json.legacy_number || '');
  const issuedDate = String(item.json.issued_date || '');
  const receivedDate = String(item.json.received_date || '');
  const corrType = String(item.json.correspondence_type || '');

  const isRFA = docNum.includes('-RFA-') || title.toLowerCase().includes('rfa');

  const systemPrompt = `You are an expert Document Controller for a construction project (LCBP3) in Thailand.
The documents are primarily in THAI and ENGLISH.
Your task is to classify documents and extract metadata from OCR text.
Respond ONLY with valid JSON.`;

  const pdfText = String(item.json.data || '').substring(0, 3500).replace(/[^a-zA-Z0-9ก-๙\s\.\/\-:\[\]\(\)]/g, ' ');

  const userPrompt = `Analyze this document:
[EXCEL METADATA]
Document Number: ${docNum || 'Not provided'}
Title: ${title || 'Not provided'}
Issued Date: ${issuedDate || 'Not provided'}
Received Date: ${receivedDate || 'Not provided'}
Correspondence Type: ${corrType || 'Not provided'}

[DATABASE REFERENCES]
Projects: ${JSON.stringify(dbProjects)}
Disciplines: ${JSON.stringify(dbDisciplines)}
Organizations: ${JSON.stringify(dbOrgs)}
Tags: ${JSON.stringify(dbTags)}
Correspondence Types: ${JSON.stringify(dbCorrTypes)}

[OCR TEXT EXTRACTION]
${pdfText}

Rules:
1. Category: Must be one of ${JSON.stringify(systemCategories)}. If Document Number contains "-RFA-", category MUST be "RFA".
2. Respond with EXACTLY 11 fields in JSON format:
   - "project_id": Find ID from table projects matching the project_code in text.
   - "discipline_id": Find ID from table disciplines analyzing text to match code_name_th. If no match, use ID=64 (from contract LCBP3-C2).
   - "sender_id": Find ID from table organizations matching Sender.
   - "receiver_id": Find ID from table organizations matching Receiver.
   - "correspondence_type_id": Find ID from table correspondence_types matching the EXCEL METADATA 'Correspondence Type'.
   - "subject": Document subject. If OCR is close to EXCEL METADATA Title, use EXCEL METADATA.
   - "issued_date": Verify from OCR text if it matches ${issuedDate}, format YYYY-MM-DD.
   - "received_date": Verify from OCR text. If empty, default to issued_date.
   - "status": Extract status (e.g., Approve, Reject, Resubmit). This will be exported as "remark".
   - "summary": 4-5 lines of Thai summary from OCR. This will be exported as "body".
   - "tags": Array of tag IDs from database matching the text. If not in DB, return string name.
   - "key_points": Array of string key points extracted.

Respond ONLY with this EXACT JSON structure:
{
  "project_id": null,
  "discipline_id": 64,
  "sender_id": null,
  "receiver_id": null,
  "correspondence_type_id": null,
  "subject": "${title}",
  "issued_date": "${issuedDate}",
  "received_date": "${receivedDate || issuedDate}",
  "status": null,
  "summary": "สรุปเนื้อหา 4-5 บรรทัด...",
  "tags": [],
  "key_points": [],
  "category": "${isRFA ? 'RFA' : 'Correspondence'}",
  "confidence": 0.95
}`;

  return {
    json: {
      ...item.json,
      active_model: model,
      is_fallback: isFallback,
      system_categories: systemCategories,
      ollama_payload: {
        model: model,
        prompt: `${systemPrompt}\n\n${userPrompt}`,
        stream: false,
        format: 'json'
      }
    }
  };
});

const ollamaItems = $input.all();
const originalItems = $('Build AI Prompt').all();
const results = [];

for (let i = 0; i < ollamaItems.length; i++) {
  const ollamaItem = ollamaItems[i];
  const originalItem = originalItems[i];
  if (!originalItem) continue;
  const baseJson = originalItem.json;

  try {
    let raw = ollamaItem.json.response || '';
    raw = raw.replace(/\x60\x60\x60json/gi, '').replace(/\x60\x60\x60/g, '').trim();
    if (!raw) throw new Error('Empty response from AI');

    const result = JSON.parse(raw);

    // Map AI result to database fields
    let tags = Array.isArray(result.tags) ? result.tags : [];

    // Enum Validation for Category
    const systemCategories = baseJson.system_categories || [];
    let finalCategory = result.category;
    if (!systemCategories.includes(finalCategory)) {
      finalCategory = String(baseJson.document_number || '').includes('-RFA-') ? 'RFA' : 'Correspondence';
    }

    results.push({
      json: {
        ...baseJson,
        ai_result: {
          suggested_category: finalCategory,
          confidence: result.confidence || 0.8,
          project_id: result.project_id,
          discipline_id: result.discipline_id || 64,
          sender_id: result.sender_id,
          receiver_id: result.receiver_id,
          correspondence_type_id: result.correspondence_type_id || null,
          subject: result.subject || baseJson.title,
          issued_date: result.issued_date || baseJson.issued_date,
          received_date: result.received_date || baseJson.received_date || result.issued_date || baseJson.issued_date,
          remark: result.status,
          body: result.summary,
          tags: tags,
          key_points: result.key_points || []
        },
        parse_error: null
      }
    });
  } catch (err) {
    results.push({
      json: {
        ...baseJson,
        ai_result: null,
        parse_error: err.message,
        raw_ai_response: ollamaItem.json.response,
        error_type: 'AI_PARSE_ERROR'
      }
    });
  }
}
return results;

const config = $('Set Configuration').first().json.config;
const items = $('Parse & Validate AI Response').all();

const results = [];

for (const item of items) {
  const data = item.json;

  // Base structure ensuring we keep all existing data
  let resultItem = { json: { ...data } };

  // Handle Parse Errors from upstream
  if (data.parse_error || !data.ai_result) {
    resultItem.json.route_index = 3;
    results.push(resultItem);
    continue;
  }

  const ai = data.ai_result;

  // Revision Drift Protection
  if (data.current_db_revision !== undefined) {
    const expectedRev = data.current_db_revision + 1;
    if (parseInt(data.excel_revision) !== expectedRev) {
      resultItem.json.review_reason = `Revision drift: Excel=${data.excel_revision}, Expected=${expectedRev}`;
      resultItem.json.route_index = 1;
      results.push(resultItem);
      continue;
    }
  }

  // Confidence Routing
  if (ai.confidence >= config.CONFIDENCE_HIGH && ai.is_valid === true) {
    resultItem.json.route_index = 0;
  } else if (ai.confidence >= config.CONFIDENCE_LOW) {
    resultItem.json.review_reason = `Confidence ${ai.confidence.toFixed(2)} < ${config.CONFIDENCE_HIGH}`;
    resultItem.json.route_index = 1;
  } else {
    resultItem.json.reject_reason = ai.is_valid === false ? 'AI marked invalid' : `Confidence ${ai.confidence.toFixed(2)} < ${config.CONFIDENCE_LOW}`;
    resultItem.json.route_index = 2;
  }
  results.push(resultItem);
}

return results;

const item = $input.first();
const shouldCheckpoint = item.json.original_index % 10 === 0;

return [{
  json: {
    ...item.json,
    should_update_checkpoint: shouldCheckpoint,
    checkpoint_index: item.json.original_index,
    import_status: 'success',
    timestamp: new Date().toISOString()
  }
}];

const fs = require('fs');
const item = $input.first();
const config = $('Set Configuration').first().json.config;

const csvPath = `${config.LOG_PATH}/reject_log.csv`;
const header = 'timestamp,document_number,title,reject_reason,ai_confidence,ai_issues\n';
const esc = (s) => `"${String(s || '').replace(/"/g, '""')}"`;

if (!fs.existsSync(csvPath)) {
  fs.writeFileSync(csvPath, header, 'utf8');
}

const line = [
  new Date().toISOString(),
  esc(item.json.document_number),
  esc(item.json.title),
  esc(item.json.reject_reason),
  item.json.ai_result?.confidence ?? 'N/A',
  esc(JSON.stringify(item.json.ai_result?.detected_issues || []))
].join(',') + '\n';

fs.appendFileSync(csvPath, line, 'utf8');

return [$input.first()];

const fs = require('fs');
const items = $input.all();
const config = $('Set Configuration').first().json.config;

const csvPath = `${config.LOG_PATH}/error_log.csv`;
const header = 'timestamp,document_number,error_type,error_message,raw_ai_response\n';
const esc = (s) => `"${String(s || '').replace(/"/g, '""')}"`;

if (!fs.existsSync(csvPath)) {
  fs.writeFileSync(csvPath, header, 'utf8');
}

for (const item of items) {
  const line = [
    new Date().toISOString(),
    esc(item.json.document_number),
    esc(item.json.error_type || 'UNKNOWN'),
    esc(item.json.error || item.json.parse_error),
    esc(item.json.raw_ai_response || '')
  ].join(',') + '\n';

  fs.appendFileSync(csvPath, line, 'utf8');
}

return items;
